import React, { useState, useEffect } from 'react';

function Marketplace() {
  const [list, setList] = useState([]);
  const [error, setError] = useState(null);

  useEffect(() => {
    // पूर्ण URL वापरल्याची खात्री कर
    fetch('http://localhost:3000/api/get')
      .then(res => {
        if (!res.ok) throw new Error("Backend कडून प्रतिसाद मिळत नाहीये");
        return res.json();
      })
      .then(data => setList(data))
      .catch(err => {
        console.error("Fetch Error:", err);
        setError("डेटा लोड होऊ शकला नाही. कृपया बॅकएंड सर्व्हर सुरू आहे का ते तपासा.");
      });
  }, []);

  return (
    <div style={{ padding: '40px' }}>
      <h1>Available Talent 🚀</h1>
      
      {error && <p style={{ color: 'red', fontWeight: 'bold' }}>{error}</p>}
      
      {list.length === 0 && !error && <p>लोड होत आहे किंवा कोणताही डेटा उपलब्ध नाही...</p>}

      <div className="freelancer-grid-new" style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(250px, 1fr))', gap: '20px' }}>
        {list.map(f => (
          <div className="freelancer-card-new" key={f._id} style={{ padding: '15px', border: '1px solid #ddd', borderRadius: '10px' }}>
            <h3>{f.name}</h3>
            <p style={{ color: '#667eea' }}>{f.skill}</p>
            <p><strong>Rate:</strong> ${f.price}/hr</p>
          </div>
        ))}
      </div>
    </div>
  );
}

export default Marketplace;
